#include <stdio.h
#include <stdlib.h>
#include <string.h
#include <unistd.h
#include <sys/types.h
#include <sys/stat.h
#include <dirent.h
#include <time.h
#include <errno.h

#define MAX_FILES 100
#define MAX_FILENAME 256
#define MAX_COMMITS 100
#define MAX_CONTENT 1024

typedef struct {
    char filename[MAX_FILENAME];
    char content[MAX_CONTENT];
} FileEntry;

typedef struct {
    int id;
    char message[256];
    time_t timestamp;
    FileEntry files[MAX_FILES];
    int file_count;
} Commit;

typedef struct {
    int version;
    char filename[MAX_FILENAME];
    char content[MAX_CONTENT];
} FileVersion;

FileVersion file_versions[MAX_FILES * MAX_COMMITS];
int file_version_count = 0;
Commit commits[MAX_COMMITS];
int commit_count = 0;
int current_version = 0;

void init_repo() {
    struct stat st = {0};
    if (stat(".minigit", &st) == -1) {
        mkdir(".minigit", 0700);
    }
}

int file_exists(const char *filename) {
    struct stat st;
    return stat(filename, &st) == 0;
}

void add_file(const char *filename) {
    FILE *fp = fopen(filename, "r");
    if (!fp) {
        fprintf(stderr, "Error: file '%s' not found\n", filename);
        exit(1);
    }

    fseek(fp, 0, SEEK_END);
    long size = ftell(fp);
    fseek(fp, 0, SEEK_SET);

    char *content = malloc(size + 1);
    fread(content, 1, size, fp);
    content[size] = '\0';
    fclose(fp);

    strcpy(file_versions[file_version_count].filename, filename);
    strcpy(file_versions[file_version_count].content, content);
    file_versions[file_version_count].version = current_version + 1;
    file_version_count++;

    free(content);
}

void commit_files(const char *message) {
    if (file_version_count == 0) {
        fprintf(stderr, "Error: no files to commit\n");
        exit(1);
    }

    commit_count++;
    current_version = commit_count;

    commits[commit_count - 1].id = commit_count;
    strcpy(commits[commit_count - 1].message, message);
    time(&commits[commit_count - 1].timestamp);
    commits[commit_count - 1].file_count = 0;

    for (int i = 0; i < file_version_count; i++) {
        if (file_versions[i].version == current_version) {
            strcpy(commits[commit_count - 1].files[commits[commit_count - 1].file_count].filename,
                   file_versions[i].filename);
            strcpy(commits[commit_count - 1].files[commits[commit_count - 1].file_count].content,
                   file_versions[i].content);
            commits[commit_count - 1].file_count++;
        }
    }
}

void checkout_version(int version) {
    if (version < 1 || version > commit_count) {
        fprintf(stderr, "Error: invalid version\n");
        exit(1);
    }

    Commit *commit = &commits[version - 1];
    for (int i = 0; i < commit->file_count; i++) {
        FILE *fp = fopen(commit->files[i].filename, "w");
        if (fp) {
            fprintf(fp, "%s", commit->files[i].content);
            fclose(fp);
        }
    }
}

void reset_version(int version) {
    if (version < 1 || version > commit_count) {
        fprintf(stderr, "Error: invalid version\n");
        exit(1);
    }

    checkout_version(version);
}

int main(int argc, char *argv[]) {
    if (argc < 2) {
        fprintf(stderr, "Usage: %s <command> [args]\n", argv[0]);
        return 1;
    }

    init_repo();

    if (strcmp(argv[1], "add") == 0) {
        if (argc < 3) {
            fprintf(stderr, "Error: no file specified\n");
            return 1;
        }
        add_file(argv[2]);
    } else if (strcmp(argv[1], "commit") == 0) {
        if (argc < 4 || strcmp(argv[2], "-m") != 0) {
            fprintf(stderr, "Error: invalid commit syntax\n");
            return 1;
        }
        commit_files(argv[3]);
    } else if (strcmp(argv[1], "checkout") == 0) {
        if (argc < 3) {
            fprintf(stderr, "Error: no version specified\n");
            return 1;
        }
        checkout_version(atoi(argv[2]));
    } else if (strcmp(argv[1], "reset") == 0) {
        if (argc < 3) {
            fprintf(stderr, "Error: no version specified\n");
            return 1;
        }
        reset_version(atoi(argv[2]));
    } else {
        fprintf(stderr, "Error: unknown command\n");
        return 1;
    }

    return 0;
}
